   303	// SnarkVM will not parse fields, groups, or scalars with leading zeros, so we strip them out.
   304	fn prepare_snarkvm_string(s: &str, suffix: &str) -> String {
   305	    // If there's a `-`, separate it from the rest of the string.
   306	    let (neg, rest) = s.strip_prefix("-").map(|rest| ("-", rest)).unwrap_or(("", s));
   307	    // Remove leading zeros.
   308	    let mut rest = rest.trim_start_matches('0');
   309	    if rest.is_empty() {
   310	        rest = "0";
   311	    }
   312	    format!("{neg}{rest}{suffix}")
   313	}
